    _reflectFee(rFee, tFee);
    emit Transfer(
      sender,
      recipient,
      balanceOf(recipient)-(recipientBalBefore)
    );
    if (rBurnAmount > 0) {
      emit Transfer(
        sender,
        deadAddress,
        balanceOf(deadAddress)-(deadBalBefore)
      );
    }
  }

  function _reflectFee(uint256 rFee, uint256 tFee) private {
